 44	      title: buildOwnerTaskTitle(group.owner_group, account, contract),
 45	      due_at: shiftIso(now, 30 + index * 30),
 46	      status: "open",
 47	      created_at: now
 48	    });
 49	  });
 50	
 51	  db.customer_messages.push({
 52	    request_id: request.request_id,
