 81	function buildOwnerTaskTitle(ownerGroup, account, contract) {
 82	  const tier = account?.tier || "account";
 83	  const supportPlan = contract?.support_plan || "support";
 84	
 85	  switch (ownerGroup) {
 86	    case "Customer Success":
 87	      return `Customer Success recovery plan for ${tier} ${supportPlan} account`;
 88	    case "Support":
 89	      return "Support investigation for delayed high-value order";
 90	    case "Finance":
 91	      return `Finance review for ${tier} account billing and contract exposure`;
 92	    case "Executive Sponsor":
 93	      return `Executive recovery oversight for ${tier} account`;
 94	    default:
 95	      return `${ownerGroup} recovery task`;
 96	  }
 97	}
