 99	function buildCustomerMessage(request, account, contract) {
100	  const tier = account?.tier || "customer";
101	  const supportPlan = contract?.support_plan || "support";
102	
103	  return `${request.customer_message} Customer-safe portal updates remain active for the ${tier} account on ${supportPlan} support, with audit-visible history preserved.`;
