106	function shiftIso(baseIso, minutes) {
107	  const date = new Date(baseIso);
108	  date.setUTCMinutes(date.getUTCMinutes() + minutes);
109	  return date.toISOString();
110	}

 1	export function buildPortalView(tables) {
 2	  const request = tables.workflow_requests[0];
 3	  const state = tables.workflow_state.find((item) => item.request_id === request.request_id);
 4	  const tasks = tables.owner_tasks
 5	    .filter((item) => item.request_id === request.request_id)
 6	    .sort((a, b) => a.group_order - b.group_order);
 7	  const auditVisible = tables.audit_events.some((item) => item.request_id === request.request_id && item.customer_visible);
 8	  const message = tables.customer_messages.find((item) => item.request_id === request.request_id);
 9	  const signals = tables.workflow_request_risk_signals
10	    .filter((item) => item.request_id === request.request_id)
11	    .sort((a, b) => a.signal_order - b.signal_order);
12	
13	  return {
14	    taskId: request.task_id,
15	    title: state?.title || request.title,
16	    status: state?.status || "Needs work",
17	    owner: tasks.length ? tasks.map((item) => item.owner_group).join(" + ") : "Unassigned",
18	    nextStep: state?.next_step || "Waiting for workflow",
19	    riskSummary: state ? `${signals.length} signals: ${signals.map((item) => item.signal_name).join(", ")}` : "Risk not scored",
20	    tasks: `${tasks.length} owner tasks`,
21	    history: auditVisible ? "Audit visible" : "Not visible",
22	    customerMessage: message?.body || "No customer-safe message"
23	  };
24	}
